function Badge({ pillar }) {
  const p = PILLARS[pillar];
  if (!p) return null;
  return <span style={{ background: p.color, color: "#fff", borderRadius: 4, padding: "2px 8px", fontSize: 11, fontWeight: 700, letterSpacing: 0.5 }}>{p.icon} {p.short}</span>;
}

function Spinner() {
  return <span style={{ display: "inline-block", width: 16, height: 16, border: "2px solid #D51317", borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.7s linear infinite", verticalAlign: "middle", marginRight: 8 }} />;
}

function MermaidBlock({ code }) {
  const [copied, setCopied] = useState(false);
  return (
    <div style={{ background: "#0f1117", borderRadius: 10, overflow: "hidden", border: "1px solid #2a2d3a" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 14px", background: "#1a1d2e", borderBottom: "1px solid #2a2d3a" }}>
        <span style={{ color: "#7c83a0", fontSize: 12, fontFamily: "monospace" }}>mermaid</span>
        <button onClick={() => { navigator.clipboard?.writeText(code); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
          style={{ background: copied ? "#00A23A" : "#2a2d3a", color: "#fff", border: "none", borderRadius: 5, padding: "4px 12px", cursor: "pointer", fontSize: 12 }}>
          {copied ? "✓ Copié !" : "📋 Copier"}
        </button>
      </div>
      <pre style={{ margin: 0, padding: "14px 16px", color: "#a8d8ea", fontSize: 12, overflowX: "auto", lineHeight: 1.7, fontFamily: "monospace", whiteSpace: "pre-wrap" }}>{code}</pre>
      <div style={{ padding: "8px 14px", background: "#1a1d2e", borderTop: "1px solid #2a2d3a", fontSize: 11, color: "#555" }}>
        💡 Coller sur <strong style={{ color: "#7c83a0" }}>mermaid.live</strong> pour visualiser
      </div>
    </div>
  );
}

function SoftwareSelector({ value, onChange, softwares, onSoftwareAdded, showSync }) {
  const [isOther, setIsOther] = useState(false);
  const [customValue, setCustomValue] = useState("");
  const [saveToList, setSaveToList] = useState(false);
  const [savingSw, setSavingSw] = useState(false);

  useEffect(() => {
    if (value && !softwares.find(s => s.name === value)) {
      setIsOther(true);
      setCustomValue(value);
    }
  }, []);

  const handleSelect = (e) => {
    const val = e.target.value;
    if (val === "__other__") { setIsOther(true); setCustomValue(""); onChange(""); }
    else { setIsOther(false); setCustomValue(""); setSaveToList(false); onChange(val); }
  };

  const handleSave = async () => {
    if (!customValue.trim()) return;
    setSavingSw(true);
    try {
      const res = await apiAddSoftware(customValue.trim());
      if (res.status === "ok") {
        onSoftwareAdded({ id: res.id, name: res.name });
        showSync("ok", `✅ "${res.name}" ajouté à la liste !`);
        setSaveToList(false); setIsOther(false); onChange(res.name);
      } else if (res.status === "duplicate") {
        showSync("error", `⚠️ "${customValue}" existe déjà.`); setSaveToList(false);
      }
    } catch { showSync("error", "❌ Erreur lors de l'ajout."); }
    setSavingSw(false);
  };

  const sel = { width: "100%", padding: "9px 12px", border: "1.5px solid #ddd", borderRadius: 7, fontSize: 14, background: "#fafafa", fontFamily: "'Roboto', sans-serif" };
  const inp = { flex: 1, padding: "9px 12px", border: "1.5px solid #D51317", borderRadius: 7, fontSize: 14, background: "#fff8f8", fontFamily: "'Roboto', sans-serif", outline: "none" };

  return (
    <div>
      <select style={sel} value={isOther ? "__other__" : (value || "")} onChange={handleSelect}>
        <option value="">— Choisir un logiciel —</option>
        {softwares.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
        <option value="__other__">✏️ Autre (préciser…)</option>
      </select>
      {isOther && (
        <div style={{ marginTop: 10 }}>
          <div style={{ display: "flex", gap: 8 }}>
            <input style={inp} placeholder="Précise le logiciel / outil…" value={customValue} onChange={e => { setCustomValue(e.target.value); onChange(e.target.value); }} autoFocus />
            <button onClick={() => { setIsOther(false); setCustomValue(""); setSaveToList(false); onChange(""); }}
              style={{ background: "#f0f0f0", border: "none", borderRadius: 7, padding: "9px 12px", cursor: "pointer", color: "#666" }}>✕</button>
          </div>
          {customValue.trim().length > 0 && (
            <div style={{ marginTop: 10, display: "flex", alignItems: "center", gap: 10, padding: "10px 14px", background: "#fff8f8", borderRadius: 8, border: "1px solid #ffcccc" }}>
              <input type="checkbox" id="saveCb" checked={saveToList} onChange={e => setSaveToList(e.target.checked)}
                style={{ width: 16, height: 16, cursor: "pointer", accentColor: "#D51317" }} />
              <label htmlFor="saveCb" style={{ fontSize: 13, color: "#555", cursor: "pointer", flex: 1 }}>
                Enregistrer <strong>"{customValue}"</strong> dans la liste partagée
              </label>
              {saveToList && (
                <button onClick={handleSave} disabled={savingSw}
                  style={{ background: savingSw ? "#ccc" : "#D51317", color: "#fff", border: "none", borderRadius: 6, padding: "6px 14px", cursor: "pointer", fontSize: 12, fontWeight: 700, whiteSpace: "nowrap" }}>
                  {savingSw ? <><Spinner />Ajout…</> : "💾 Ajouter"}
                </button>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default function App() {
  const [tab, setTab] = useState("overview");
  const [tasks, setTasks] = useState([]);
  const [softwares, setSoftwares] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [syncMsg, setSyncMsg] = useState(null);
  const [form, setForm] = useState({ ...TASK_TEMPLATE });
  const [editId, setEditId] = useState(null);
  const [filterPillar, setFilterPillar] = useState("ALL");
  const [filterDept, setFilterDept] = useState("ALL");
  const [mermaidMode, setMermaidMode] = useState("global");
  const [versionLog, setVersionLog] = useState([{ v: 1, ts: new Date().toLocaleString("fr-BE"), desc: "Connexion à Google Sheets…" }]);

  useEffect(() => {
    setLoading(true);
    Promise.all([apiFetch({ action: "getTasks" }), apiFetch({ action: "getSoftwares" })])
      .then(([td, sd]) => {
        if (td.status === "ok") setTasks(td.tasks || []);
        if (sd.status === "ok") setSoftwares(sd.softwares || []);
        setVersionLog(l => [...l, { v: 2, ts: new Date().toLocaleString("fr-BE"), desc: `✅ ${td.tasks?.length || 0} tâche(s) et ${sd.softwares?.length || 0} logiciel(s) chargés` }]);
      })
      .catch(() => showSync("error", "❌ Impossible de contacter Google Sheets."))
      .finally(() => setLoading(false));
  }, []);

  const showSync = (type, text) => { setSyncMsg({ type, text }); setTimeout(() => setSyncMsg(null), 4000); };

  const saveTask = async () => {
    if (!form.DeptID || !form.TaskName) return;
    setSaving(true);
    const task = { ...form, TaskID: editId || uid(), CreatedAt: form.CreatedAt || new Date().toLocaleString("fr-BE"), Version: String(tasks.length + 1) };
    try {
      await apiSaveTask(task);
      if (editId) {
        setTasks(p => p.map(t => t.TaskID === editId ? task : t));
        setVersionLog(l => [...l, { v: l.length + 1, ts: new Date().toLocaleString("fr-BE"), desc: `✏️ Modification: "${task.TaskName}"` }]);
        showSync("ok", "✅ Tâche modifiée !");
      } else {
        setTasks(p => [...p, task]);
        setVersionLog(l => [...l, { v: l.length + 1, ts: new Date().toLocaleString("fr-BE"), desc: `➕ Ajout: "${task.TaskName}" → ${task.DeptID}` }]);
        showSync("ok", "✅ Tâche sauvegardée dans Google Sheets !");
      }
      setForm({ ...TASK_TEMPLATE }); setEditId(null);
    } catch { showSync("error", "❌ Erreur de sauvegarde."); }
    setSaving(false);
  };

  const deleteTask = async (id) => {
    if (!window.confirm("Supprimer cette tâche ?")) return;
    try {
      await apiDeleteTask(id);
      setTasks(p => p.filter(t => t.TaskID !== id));
      setVersionLog(l => [...l, { v: l.length + 1, ts: new Date().toLocaleString("fr-BE"), desc: `🗑️ Suppression tâche ${id}` }]);
      showSync("ok", "✅ Tâche supprimée.");
    } catch { showSync("error", "❌ Erreur."); }
  };

  const editTask = (t) => { setForm({ ...t }); setEditId(t.TaskID); setTab("input"); };
  const filteredTasks = useMemo(() => tasks.filter(t =>
    (filterPillar === "ALL" || DEPARTMENTS_INIT.find(d => d.id === t.DeptID)?.pillar === filterPillar) &&
    (filterDept === "ALL" || t.DeptID === filterDept)
  ), [tasks, filterPillar, filterDept]);
  const mermaidCode = useMemo(() => mermaidMode === "global" ? generateMermaid(tasks) : generateMermaidPillar(tasks, mermaidMode), [tasks, mermaidMode]);
  const totalHC = DEPARTMENTS_INIT.reduce((a, b) => a + b.headcount, 0);
  const deptsByPillar = (pk) => DEPARTMENTS_INIT.filter(d => d.pillar === pk);
  const tasksByDept = (id) => tasks.filter(t => t.DeptID === id);

  const BRAND = {
    red: "#D51317",
    green: "#8CBE26",
    blue: "#005CA9",
    lightGreen: "#c8e6d8",
    lightBlue: "#b8d8f0",
    bgGradient: "linear-gradient(160deg, #d4ecd8 0%, #c8e6d8 40%, #b8d8f0 100%)",
  };

  const S = {
    app: { fontFamily: "'Roboto', 'Segoe UI', sans-serif", background: BRAND.bgGradient, minHeight: "100vh", color: "#1a1a2e" },
    header: { background: `linear-gradient(135deg, #1a0a0a 0%, #2d0f0f 50%, ${BRAND.red} 100%)`, padding: "0", position: "relative", overflow: "hidden" },
    headerInner: { padding: "20px 32px 0 32px", display: "flex", justifyContent: "space-between", alignItems: "center" },
    redBar: { height: 8, background: BRAND.red, marginTop: 0 },
    tabs: { display: "flex", background: "rgba(255,255,255,0.92)", backdropFilter: "blur(8px)", borderBottom: "3px solid " + BRAND.red, padding: "0 24px", overflowX: "auto", boxShadow: "0 2px 12px rgba(213,19,23,0.1)" },
    tab: (a) => ({ padding: "14px 18px", border: "none", background: "none", cursor: "pointer", fontWeight: a ? 700 : 500, color: a ? BRAND.red : "#555", borderBottom: a ? `3px solid ${BRAND.red}` : "3px solid transparent", marginBottom: -3, fontSize: 13, whiteSpace: "nowrap", fontFamily: "'Roboto', sans-serif" }),
    body: { padding: "24px 32px", maxWidth: 1100, margin: "0 auto" },
    card: { background: "rgba(255,255,255,0.92)", backdropFilter: "blur(4px)", borderRadius: 14, padding: 20, boxShadow: "0 4px 20px rgba(0,0,0,0.08)", marginBottom: 20 },
    input: { width: "100%", padding: "9px 12px", border: "1.5px solid #ddd", borderRadius: 7, fontSize: 14, boxSizing: "border-box", background: "#fafafa", fontFamily: "'Roboto', sans-serif" },
    select: { width: "100%", padding: "9px 12px", border: "1.5px solid #ddd", borderRadius: 7, fontSize: 14, boxSizing: "border-box", background: "#fafafa", fontFamily: "'Roboto', sans-serif" },
    label: { fontSize: 12, fontWeight: 700, color: "#555", marginBottom: 4, display: "block", textTransform: "uppercase", letterSpacing: 0.5, fontFamily: "'Roboto', sans-serif" },
    btn: (c) => ({ background: c, color: "#fff", border: "none", borderRadius: 7, padding: "10px 20px", cursor: "pointer", fontWeight: 700, fontSize: 13, fontFamily: "'Roboto', sans-serif" }),
    pill: (c, bg) => ({ background: bg, color: c, border: `1px solid ${c}30`, borderRadius: 20, padding: "3px 10px", fontSize: 11, fontWeight: 600, display: "inline-block" }),
    th: { padding: "10px 14px", textAlign: "left", fontSize: 11, fontWeight: 700, color: "#888", textTransform: "uppercase", background: "rgba(213,19,23,0.04)", borderBottom: `2px solid ${BRAND.red}20` },
    td: { padding: "10px 14px", fontSize: 13, borderBottom: "1px solid #f0efeb", verticalAlign: "middle" },
    sectionTitle: { fontFamily: "'BROTHER', sans-serif", letterSpacing: 1 },
  };

  const GLOBAL_CSS = `
    @import url('https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;500;700;900&display=swap');
    @font-face {
      font-family: 'BROTHER';
      src: url('data:font/truetype;base64,' + BROTHER_FONT + ') format('truetype');
      font-weight: bold;
      font-style: normal;
    }
    @keyframes spin { to { transform: rotate(360deg); } }
    @keyframes float { 0%,100% { transform: translateY(0px); } 50% { transform: translateY(-8px); } }
    @keyframes floatR { 0%,100% { transform: translateY(0px) scaleX(-1); } 50% { transform: translateY(-6px) scaleX(-1); } }
    tr:hover td { background: rgba(213,19,23,0.02); }
    * { box-sizing: border-box; }
  `;

  return (
    <div style={S.app}>
      <style>{GLOBAL_CSS}</style>

      {/* ── HEADER ── */}
      <div style={S.header}>
        {/* Clouds decoration */}
        <div style={{ position: "absolute", top: 8, left: "15%", opacity: 0.15 }}>
          <svg width="80" height="30" viewBox="0 0 80 30"><ellipse cx="40" cy="20" rx="35" ry="15" fill="white"/><ellipse cx="25" cy="18" rx="18" ry="12" fill="white"/><ellipse cx="55" cy="16" rx="20" ry="13" fill="white"/></svg>
        </div>
        <div style={{ position: "absolute", top: 4, right: "20%", opacity: 0.12 }}>
          <svg width="60" height="22" viewBox="0 0 60 22"><ellipse cx="30" cy="14" rx="26" ry="10" fill="white"/><ellipse cx="18" cy="13" rx="14" ry="9" fill="white"/><ellipse cx="42" cy="12" rx="15" ry="9" fill="white"/></svg>
        </div>

        <div style={S.headerInner}>
          <div style={{ display: "flex", alignItems: "center", gap: 20 }}>
            <img src="https://www.colona.be/wp-content/themes/colona/src/images/logo.svg" alt="Colona" style={{ height: 56, filter: "brightness(0) invert(1)" }} onError={e => e.target.style.display="none"} />
            <div>
              <div style={{ ...S.sectionTitle, color: "#fff", fontSize: 20, fontWeight: 800, letterSpacing: 3 }}>BUSINESS PROCESS ANALYSIS</div>
              <div style={{ color: "rgba(255,255,255,0.7)", fontSize: 11, letterSpacing: 4, marginTop: 2, textTransform: "uppercase" }}>Waremme — Since 1963</div>
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "flex-end", gap: 24 }}>
            {/* Characters in header */}
            <div style={{ animation: "float 3s ease-in-out infinite", marginBottom: -4 }}><CharacterFries /></div>
            <div style={{ animation: "float 3.5s ease-in-out infinite 0.5s", marginBottom: -4 }}><CharacterTomato /></div>
            <div style={{ textAlign: "right" }}>
              <div style={{ color: "#FDCA00", fontWeight: 800, fontSize: 20, fontFamily: "'BROTHER', sans-serif", letterSpacing: 1 }}>
                {loading ? <><Spinner />Chargement…</> : `${tasks.length} TÂCHE${tasks.length !== 1 ? "S" : ""}`}
              </div>
              <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 11, marginTop: 2 }}>
                {loading ? "Connexion…" : "✅ Sync Google Sheets"}
              </div>
            </div>
          </div>
        </div>
        <div style={S.redBar} />
      </div>

      {/* ── SYNC MSG ── */}
      {syncMsg && (
        <div style={{ background: syncMsg.type === "ok" ? "#e6f7ed" : "#fdecea", borderBottom: `3px solid ${syncMsg.type === "ok" ? BRAND.green : BRAND.red}`, padding: "10px 32px", fontSize: 13, fontWeight: 600, color: syncMsg.type === "ok" ? "#00A23A" : BRAND.red }}>
          {syncMsg.text}
        </div>
      )}

      {/* ── TABS ── */}
      <div style={S.tabs}>
        {[["overview","🏠 Vue d'ensemble"],["input","✏️ Saisie"],["tasks","📋 Tâches"],["taxonomy","🗂️ Taxonomie"],["mermaid","📊 Mermaid"],["versioning","🕓 Historique"],["softwares","💻 Logiciels"]].map(([k,l]) => (
          <button key={k} style={S.tab(tab === k)} onClick={() => setTab(k)}>{l}</button>
        ))}
      </div>

      <div style={S.body}>

        {/* ══ OVERVIEW ══ */}
        {tab === "overview" && (
          <div>
            {/* Pillar cards */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 16, marginBottom: 24 }}>
              {Object.entries(PILLARS).map(([pk, pv]) => (
                <div key={pk} style={{ background: pv.color, borderRadius: 14, padding: "20px 24px", color: "#fff", boxShadow: `0 6px 24px ${pv.color}60`, position: "relative", overflow: "hidden" }}>
                  <div style={{ position: "absolute", right: -10, bottom: -10, opacity: 0.12, fontSize: 80 }}>{pv.icon}</div>
                  <div style={{ ...S.sectionTitle, fontWeight: 800, fontSize: 16, color: "#fff", marginBottom: 4 }}>{pv.icon} {pv.label}</div>
                  <div style={{ fontSize: 12, opacity: 0.85, marginBottom: 14 }}>{pv.desc}</div>
                  <div style={{ display: "flex", gap: 20 }}>
                    <div><div style={{ ...S.sectionTitle, fontSize: 28, fontWeight: 800 }}>{deptsByPillar(pk).length}</div><div style={{ fontSize: 10, opacity: 0.8 }}>depts</div></div>
                    <div><div style={{ ...S.sectionTitle, fontSize: 28, fontWeight: 800 }}>{deptsByPillar(pk).reduce((a,d)=>a+d.headcount,0)}</div><div style={{ fontSize: 10, opacity: 0.8 }}>employés</div></div>
                    <div><div style={{ ...S.sectionTitle, fontSize: 28, fontWeight: 800 }}>{tasks.filter(t=>deptsByPillar(pk).find(d=>d.id===t.DeptID)).length}</div><div style={{ fontSize: 10, opacity: 0.8 }}>tâches</div></div>
                  </div>
                </div>
              ))}
            </div>

            {/* Departments grid */}
            <div style={S.card}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                <h3 style={{ ...S.sectionTitle, margin: 0, fontSize: 16, color: BRAND.red }}>25 DÉPARTEMENTS COLONA</h3>
                <div style={{ animation: "floatR 4s ease-in-out infinite" }}><CharacterPepper /></div>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(230px, 1fr))", gap: 8 }}>
                {DEPARTMENTS_INIT.map(d => (
                  <div key={d.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 12px", background: "rgba(255,255,255,0.7)", borderRadius: 8, border: `1px solid ${PILLARS[d.pillar].color}20` }}>
                    <Badge pillar={d.pillar} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 700, fontSize: 13, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{d.name}</div>
                      <div style={{ fontSize: 11, color: "#999", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{d.manager}</div>
                    </div>
                    <div style={{ fontSize: 12, fontWeight: 700, color: "#666" }}>{d.headcount || "—"}</div>
                    {tasksByDept(d.id).length > 0 && <div style={{ width: 8, height: 8, borderRadius: "50%", background: BRAND.green, flexShrink: 0 }} />}
                  </div>
                ))}
              </div>
              <div style={{ marginTop: 14, padding: "10px 14px", background: `rgba(213,19,23,0.04)`, borderRadius: 8, fontSize: 13, color: "#555", borderLeft: `4px solid ${BRAND.red}` }}>
                👥 <strong>{totalHC}</strong> employés · 25 départements · 🟢 = tâches encodées · 💻 <strong>{softwares.length}</strong> logiciels
              </div>
            </div>
          </div>
        )}

        {/* ══ SAISIE ══ */}
        {tab === "input" && (
          <div style={S.card}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 20 }}>
              <h3 style={{ ...S.sectionTitle, margin: 0, color: BRAND.red, fontSize: 16 }}>{editId ? "✏️ MODIFIER LA TÂCHE" : "➕ ENCODER UNE NOUVELLE TÂCHE"}</h3>
              <div style={{ animation: "float 3s ease-in-out infinite" }}><CharacterBurger /></div>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              <div>
                <label style={S.label}>🏢 Département *</label>
                <select style={S.select} value={form.DeptID} onChange={e => setForm(f => ({ ...f, DeptID: e.target.value }))}>
                  <option value="">— Choisir —</option>
                  {Object.entries(PILLARS).map(([pk, pv]) => (
                    <optgroup key={pk} label={`${pv.icon} ${pv.label}`}>
                      {DEPARTMENTS_INIT.filter(d => d.pillar === pk).map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                    </optgroup>
                  ))}
                </select>
              </div>
              <div>
                <label style={S.label}>📝 Nom de la tâche *</label>
                <input style={S.input} placeholder="Ex: Valider bon de commande fournisseur" value={form.TaskName} onChange={e => setForm(f => ({ ...f, TaskName: e.target.value }))} />
              </div>
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={S.label}>💻 Logiciel / Outil</label>
                <SoftwareSelector value={form.Software} onChange={val => setForm(f => ({ ...f, Software: val }))} softwares={softwares} onSoftwareAdded={(sw) => setSoftwares(p => [...p, sw])} showSync={showSync} />
              </div>
              <div>
                <label style={S.label}>📅 Fréquence</label>
                <select style={S.select} value={form.Frequency} onChange={e => setForm(f => ({ ...f, Frequency: e.target.value }))}>
                  {FREQUENCIES.map(fr => <option key={fr}>{fr}</option>)}
                </select>
              </div>
              <div>
                <label style={S.label}>🔗 URL Document / Procédure</label>
                <input style={S.input} type="url" placeholder="https://sharepoint.com/… ou lien Drive" value={form.DocURL || ""} onChange={e => setForm(f => ({ ...f, DocURL: e.target.value }))} />
              </div>
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={S.label}>🔗 Dépendances — Cliquer sur les départements liés</label>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6, padding: "10px 12px", border: "1.5px solid #ddd", borderRadius: 7, background: "#fafafa", minHeight: 44 }}>
                  {DEPARTMENTS_INIT.filter(d => d.id !== form.DeptID).map(d => {
                    const cur = form.Deps ? form.Deps.split(",").map(s => s.trim()).filter(Boolean) : [];
                    const active = cur.includes(d.id);
                    return (
                      <button key={d.id} onClick={() => {
                        const deps = form.Deps ? form.Deps.split(",").map(s => s.trim()).filter(Boolean) : [];
                        setForm(f => ({ ...f, Deps: (active ? deps.filter(x => x !== d.id) : [...deps, d.id]).join(",") }));
                      }} style={{ padding: "4px 10px", borderRadius: 20, border: `1.5px solid ${active ? PILLARS[d.pillar].color : "#ccc"}`, background: active ? PILLARS[d.pillar].color : "#fff", color: active ? "#fff" : "#555", fontSize: 12, cursor: "pointer", fontWeight: active ? 700 : 400 }}>
                        {d.name}
                      </button>
                    );
                  })}
                </div>
                {form.Deps && <div style={{ fontSize: 12, color: BRAND.green, marginTop: 6 }}>✓ {form.Deps.split(",").filter(Boolean).length} dépendance(s)</div>}
              </div>
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={S.label}>💬 Notes</label>
                <input style={S.input} placeholder="Volume, contraintes, particularités…" value={form.Notes} onChange={e => setForm(f => ({ ...f, Notes: e.target.value }))} />
              </div>
            </div>
            <div style={{ marginTop: 20, display: "flex", gap: 10, alignItems: "center" }}>
              <button style={S.btn(!form.DeptID || !form.TaskName || saving ? "#ccc" : BRAND.red)} onClick={saveTask} disabled={!form.DeptID || !form.TaskName || saving}>
                {saving ? <><Spinner />Sauvegarde…</> : editId ? "💾 Enregistrer" : "➕ Ajouter la tâche"}
              </button>
              {editId && <button style={S.btn("#95a5a6")} onClick={() => { setForm({ ...TASK_TEMPLATE }); setEditId(null); }}>Annuler</button>}
            </div>
            {form.DeptID && (() => { const d = DEPARTMENTS_INIT.find(x => x.id === form.DeptID); const p = PILLARS[d.pillar]; return (
              <div style={{ marginTop: 14, padding: "10px 14px", background: p.bg, borderRadius: 8, fontSize: 13, borderLeft: `4px solid ${p.color}` }}>
                {p.icon} <strong>{d.name}</strong> · <strong style={{ color: p.color }}>{p.label}</strong> · {d.manager}
              </div>
            ); })()}
          </div>
        )}

        {/* ══ TÂCHES ══ */}
        {tab === "tasks" && (
          <div>
            <div style={{ display: "flex", gap: 12, marginBottom: 16, flexWrap: "wrap" }}>
              <div style={{ flex: 1, minWidth: 160 }}>
                <label style={S.label}>Pilier</label>
                <select style={S.select} value={filterPillar} onChange={e => setFilterPillar(e.target.value)}>
                  <option value="ALL">Tous</option>
                  {Object.entries(PILLARS).map(([k,v]) => <option key={k} value={k}>{v.icon} {v.label}</option>)}
                </select>
              </div>
              <div style={{ flex: 1, minWidth: 160 }}>
                <label style={S.label}>Département</label>
                <select style={S.select} value={filterDept} onChange={e => setFilterDept(e.target.value)}>
                  <option value="ALL">Tous</option>
                  {DEPARTMENTS_INIT.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                </select>
              </div>
              <div style={{ flex: 1, minWidth: 160, display: "flex", alignItems: "flex-end" }}>
                <div style={{ padding: "10px 16px", background: "rgba(0,162,58,0.1)", borderRadius: 8, fontSize: 13, color: BRAND.green, fontWeight: 700, border: `1px solid ${BRAND.green}40` }}>{filteredTasks.length} tâche{filteredTasks.length !== 1 ? "s" : ""}</div>
              </div>
            </div>
            {loading ? (
              <div style={{ ...S.card, textAlign: "center", padding: 48, color: "#aaa" }}><Spinner />Chargement…</div>
            ) : filteredTasks.length === 0 ? (
              <div style={{ ...S.card, textAlign: "center", padding: 48 }}>
                <div style={{ marginBottom: 12 }}><CharacterFries /></div>
                <div style={{ fontWeight: 600, color: "#999" }}>Aucune tâche encodée — utilise l'onglet Saisie !</div>
              </div>
            ) : (
              <div style={{ ...S.card, padding: 0, overflow: "hidden" }}>
                <table style={{ width: "100%", borderCollapse: "collapse" }}>
                  <thead><tr>{["Pilier","Département","Tâche","Logiciel","Fréquence","Document","Dépendances","Actions"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
                  <tbody>
                    {filteredTasks.map(t => {
                      const dept = DEPARTMENTS_INIT.find(d => d.id === t.DeptID); if (!dept) return null;
                      const deps = t.Deps ? t.Deps.split(",").map(s => s.trim()).filter(Boolean) : [];
                      return (
                        <tr key={t.TaskID}>
                          <td style={S.td}><Badge pillar={dept.pillar} /></td>
                          <td style={S.td}><strong>{dept.name}</strong></td>
                          <td style={S.td}><strong>{t.TaskName}</strong>{t.Notes && <div style={{ fontSize: 11, color: "#aaa" }}>{t.Notes}</div>}</td>
                          <td style={S.td}><span style={S.pill(BRAND.blue,"#e6eef8")}>{t.Software || "N/A"}</span></td>
                          <td style={S.td}><span style={S.pill("#8e44ad","#f5eef8")}>{t.Frequency}</span></td>
                          <td style={S.td}>{t.DocURL ? <a href={t.DocURL} target="_blank" rel="noreferrer" style={{ color: BRAND.red, fontWeight: 600, fontSize: 12, textDecoration: "none" }}>📎 Voir doc</a> : <span style={{ color: "#ccc", fontSize: 12 }}>—</span>}</td>
                          <td style={S.td}>{deps.length > 0 ? <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>{deps.map(did => { const dd = DEPARTMENTS_INIT.find(d => d.id === did); return dd ? <span key={did} style={S.pill(PILLARS[dd.pillar].color, PILLARS[dd.pillar].bg)}>{dd.name}</span> : null; })}</div> : <span style={{ color: "#ccc" }}>—</span>}</td>
                          <td style={S.td}>
                            <button onClick={() => editTask(t)} style={{ background: "#f0f0f8", border: "none", borderRadius: 5, padding: "5px 10px", cursor: "pointer", marginRight: 4 }}>✏️</button>
                            <button onClick={() => deleteTask(t.TaskID)} style={{ background: "#fdecea", border: "none", borderRadius: 5, padding: "5px 10px", cursor: "pointer" }}>🗑️</button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {/* ══ TAXONOMIE ══ */}
        {tab === "taxonomy" && (
          <div>
            <div style={{ ...S.card, borderLeft: `4px solid ${BRAND.red}`, background: "rgba(255,255,255,0.92)" }}>
              <h3 style={{ ...S.sectionTitle, margin: "0 0 8px", fontSize: 16, color: BRAND.red }}>TAXONOMIE — 3 PILIERS COLONA</h3>
              <p style={{ margin: 0, fontSize: 13, color: "#666" }}>Flux transversaux inter-piliers détectés automatiquement.</p>
            </div>
            {Object.entries(PILLARS).map(([pk, pv]) => {
              const depts = deptsByPillar(pk);
              const ptasks = tasks.filter(t => depts.find(d => d.id === t.DeptID));
              return (
                <div key={pk} style={{ ...S.card, borderTop: `4px solid ${pv.color}` }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
                    <div>
                      <div style={{ ...S.sectionTitle, fontSize: 16 }}>{pv.icon} <strong style={{ color: pv.color }}>{pv.label}</strong></div>
                      <div style={{ fontSize: 13, color: "#666", marginTop: 4 }}>{pv.desc}</div>
                    </div>
                    <div style={{ textAlign: "right" }}><div style={{ ...S.sectionTitle, fontSize: 28, fontWeight: 800, color: pv.color }}>{ptasks.length}</div><div style={{ fontSize: 11, color: "#aaa" }}>tâches</div></div>
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))", gap: 8 }}>
                    {depts.map(d => {
                      const ts = tasksByDept(d.id);
                      return (
                        <div key={d.id} style={{ padding: "10px 14px", background: pv.bg, borderRadius: 8, border: `1px solid ${pv.color}30` }}>
                          <div style={{ fontWeight: 700, fontSize: 13 }}>{d.name}</div>
                          <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>{d.headcount > 0 ? `${d.headcount} emp.` : "Transverse"}</div>
                          {ts.length > 0 && <div style={{ marginTop: 8 }}>{ts.map(t => <div key={t.TaskID} style={{ fontSize: 11, padding: "2px 6px", background: "rgba(255,255,255,0.7)", borderRadius: 4, marginBottom: 3 }}>▸ {t.TaskName}</div>)}</div>}
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}
            {tasks.some(t => (t.Deps || "").trim()) && (
              <div style={{ ...S.card, borderLeft: "4px solid #9b59b6" }}>
                <h3 style={{ ...S.sectionTitle, margin: "0 0 14px", color: "#9b59b6", fontSize: 14 }}>FLUX TRANSVERSAUX DÉTECTÉS</h3>
                {tasks.filter(t => (t.Deps || "").trim()).map(t => {
                  const src = DEPARTMENTS_INIT.find(d => d.id === t.DeptID); if (!src) return null;
                  const deps = t.Deps.split(",").map(s => s.trim()).filter(Boolean);
                  const isInter = deps.some(did => DEPARTMENTS_INIT.find(d => d.id === did)?.pillar !== src.pillar);
                  return (
                    <div key={t.TaskID} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10, fontSize: 13, flexWrap: "wrap" }}>
                      <Badge pillar={src.pillar} /><strong>{src.name}</strong>
                      <span style={{ color: "#aaa" }}>→ "{t.TaskName}" →</span>
                      {deps.map(did => { const dd = DEPARTMENTS_INIT.find(d => d.id === did); return dd ? <span key={did}><Badge pillar={dd.pillar} /> <strong>{dd.name}</strong></span> : null; })}
                      {isInter && <span style={{ background: "#9b59b6", color: "#fff", borderRadius: 10, padding: "2px 8px", fontSize: 10, fontWeight: 700 }}>⚡ INTER-PILIER</span>}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {/* ══ MERMAID ══ */}
        {tab === "mermaid" && (
          <div>
            <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
              {[["global","🌐 Vue globale"],["P2S","🏭 Produce-to-Stock"],["O2C","📦 Order-to-Cash"],["E2O","⚙️ Enable-to-Operate"]].map(([k,l]) => (
                <button key={k} onClick={() => setMermaidMode(k)} style={{ padding: "9px 18px", borderRadius: 8, border: `2px solid ${mermaidMode === k ? BRAND.red : "#ddd"}`, background: mermaidMode === k ? "rgba(213,19,23,0.08)" : "rgba(255,255,255,0.8)", fontWeight: mermaidMode === k ? 700 : 400, cursor: "pointer", fontSize: 13, color: mermaidMode === k ? BRAND.red : "#555" }}>{l}</button>
              ))}
            </div>
            {tasks.length === 0 ? (
              <div style={{ ...S.card, textAlign: "center", padding: 48 }}>
                <div style={{ marginBottom: 12 }}><CharacterBurger /></div>
                <div style={{ fontWeight: 600, color: "#999" }}>Encode d'abord des tâches avec des dépendances</div>
              </div>
            ) : (
              <div>
                <MermaidBlock code={mermaidCode} />
                <div style={{ ...S.card, marginTop: 16, background: "rgba(0,92,169,0.06)", border: `1px solid ${BRAND.blue}20` }}>
                  <h4 style={{ ...S.sectionTitle, margin: "0 0 10px", color: BRAND.blue, fontSize: 13 }}>🚀 VISUALISER</h4>
                  <ol style={{ margin: 0, paddingLeft: 20, fontSize: 13, color: "#555", lineHeight: 2 }}>
                    <li>Copier via <strong>📋 Copier</strong></li><li>Ouvrir <strong>mermaid.live</strong></li><li>Coller → diagramme instantané</li>
                  </ol>
                </div>
              </div>
            )}
          </div>
        )}

        {/* ══ HISTORIQUE ══ */}
        {tab === "versioning" && (
          <div>
            <div style={{ ...S.card, borderLeft: `4px solid ${BRAND.green}` }}>
              <h3 style={{ ...S.sectionTitle, margin: "0 0 8px", color: BRAND.green, fontSize: 15 }}>JOURNAL DES VERSIONS</h3>
              <p style={{ margin: "0 0 16px", fontSize: 13, color: "#666" }}>Chaque action est tracée ici et persistée dans Google Sheets.</p>
              <div style={{ borderLeft: `3px solid ${BRAND.green}`, paddingLeft: 20 }}>
                {[...versionLog].reverse().map((e, i) => (
                  <div key={i} style={{ marginBottom: 16, position: "relative" }}>
                    <div style={{ position: "absolute", left: -26, top: 2, width: 10, height: 10, borderRadius: "50%", background: i === 0 ? BRAND.green : "#ccc", border: "2px solid #fff" }} />
                    <div><span style={{ fontWeight: 800, color: BRAND.green }}>v{e.v}</span><span style={{ fontSize: 11, color: "#aaa", marginLeft: 12 }}>{e.ts}</span></div>
                    <div style={{ fontSize: 13, color: "#555", marginTop: 2 }}>{e.desc}</div>
                  </div>
                ))}
              </div>
            </div>
            <div style={{ ...S.card }}>
              <h4 style={{ ...S.sectionTitle, margin: "0 0 12px", fontSize: 14, color: BRAND.red }}>STATISTIQUES</h4>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12 }}>
                {[["📝 Tâches", tasks.length, BRAND.red],["🔗 Avec dépendances", tasks.filter(t=>(t.Deps||"").trim()).length, "#9b59b6"],["🏢 Depts actifs", new Set(tasks.map(t=>t.DeptID)).size, BRAND.blue],["💻 Logiciels", softwares.length, "#EB6011"]].map(([l,v,c]) => (
                  <div key={l} style={{ padding: "14px 16px", background: "rgba(255,255,255,0.8)", borderRadius: 10, border: `1px solid ${c}20`, textAlign: "center", borderTop: `3px solid ${c}` }}>
                    <div style={{ ...S.sectionTitle, fontSize: 28, fontWeight: 800, color: c }}>{v}</div>
                    <div style={{ color: "#666", marginTop: 4, fontSize: 12 }}>{l}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ══ LOGICIELS ══ */}
        {tab === "softwares" && (
          <div>
            <div style={{ ...S.card, borderLeft: `4px solid ${BRAND.blue}` }}>
              <h3 style={{ ...S.sectionTitle, margin: "0 0 8px", color: BRAND.blue, fontSize: 15 }}>GESTION DES LOGICIELS</h3>
              <p style={{ margin: 0, fontSize: 13, color: "#666" }}>Liste synchronisée avec Google Sheets — visible par tous les utilisateurs.</p>
            </div>
            <div style={{ ...S.card, padding: 0, overflow: "hidden" }}>
              <table style={{ width: "100%", borderCollapse: "collapse" }}>
                <thead><tr>{["#","ID","Nom du logiciel","Utilisé dans"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
                <tbody>
                  {softwares.map((sw, i) => {
                    const usage = tasks.filter(t => t.Software === sw.name).length;
                    return (
                      <tr key={sw.id}>
                        <td style={{ ...S.td, color: "#aaa", width: 40 }}>{i + 1}</td>
                        <td style={{ ...S.td, width: 80 }}><span style={S.pill(BRAND.blue,"#e6eef8")}>{sw.id}</span></td>
                        <td style={{ ...S.td, fontWeight: 700 }}>{sw.name}</td>
                        <td style={S.td}>{usage > 0 ? <span style={S.pill(BRAND.green,"#e6f7ed")}>{usage} tâche{usage > 1 ? "s" : ""}</span> : <span style={{ color: "#ccc", fontSize: 12 }}>Non utilisé</span>}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
            <div style={{ ...S.card, background: "rgba(255,255,255,0.6)", fontSize: 13, color: "#666" }}>
              💡 Pour ajouter un logiciel, utilise <strong>"Autre"</strong> dans <strong>✏️ Saisie</strong> et coche la case d'enregistrement.
            </div>
          </div>
        )}

        {/* Footer character */}
        <div style={{ textAlign: "center", padding: "20px 0 8px", opacity: 0.5 }}>
          <img src="https://www.colona.be/wp-content/themes/colona/src/images/logo.svg" alt="Colona" style={{ height: 28 }} onError={e => e.target.style.display="none"} />
        </div>

      </div>

      {/* ── RED BOTTOM BAR ── */}
      <div style={{ height: 8, background: BRAND.red, marginTop: 8 }} />
    </div>
  );
}
